      options: [{ id: `A`, text: `Most surveyed visitors to the Museo Reina Sof&iacute;a indicated that they lived somewhere other than Madrid.` }, { id: `B`, text: `Many surveyed visitors to the Museo Reina Sof&iacute;a indicated that the virtual tours convinced them to plan an in-person visit.` }, { id: `C`, text: `Many surveyed visitors to the Museo Reina Sof&iacute;a indicated that they would likely view the virtual tours in order to reminisce about their in-person visit.` }, { id: `D`, text: `Most surveyed visitors to the Museo Reina Sof&iacute;a indicated that they were unaware of the virtual tours before their first in-person visit.` }],
